select 
from note
where 1=1


  and user_id = #{queryDTO.userId}



  and exists (select 1 from admin a where a.id = note.user_id)


  and deleted = #{queryDTO.isDeleted}


  and deleted = 0



  and delete_time >= DATE_SUB(NOW(), INTERVAL 15 DAY)


  and id in (
  select note_id from note_category_relation
  where category_id = #{queryDTO.categoryId}
  )


  and is_starred = #{queryDTO.onlyStarred}


  and title like concat('%', #{queryDTO.title}, '%')


  and user_id in (
  select id from admin
  where user_code like concat('%', #{queryDTO.ownerUserCode}, '%')
  or name like concat('%', #{queryDTO.ownerUserCode}, '%')

  or id = #{queryDTO.ownerAdminId}

  )

